    "song_title": "Alexander Hamilton",
    "song_title_zh": "",
    "song_id": "01-alexander-hamilton",
    "line_index": "18",
    "english": "Put a pencil to his temple, connected it to his brain",
    "ipa": "/pʊt ɐ pɛnsəl tə hɪz tɛmpəl kənɛktᵻd ɪt tə hɪz bɹeɪn/",
