    "song_order": "1",
    "song_title": "Alexander Hamilton",
    "song_title_zh": "",
    "song_id": "01-alexander-hamilton",
    "line_index": "26",
    "english": "And there's a million things I haven't done",
    "ipa": "/ænd ðɛɹz ɐ mɪliən θɪŋz aɪ hævənt dʌn/",
