    "song_title_zh": "",
    "song_id": "03-my-shot",
    "line_index": "81",
    "english": "I never had a group of friends before",
    "ipa": "/aɪ nɛvɚ hæd ɐ ɡɹup ʌv fɹɛndz bᵻfɔɹ/",
    "chinese_translation": "我从来没有这么多的朋友",
