    "song_order": "5",
    "song_title": "The Schuyler Sisters",
    "song_title_zh": "",
    "song_id": "05-the-schuyler-sisters",
    "line_index": "1",
    "english": "There's nothing rich folks love more",
    "ipa": "/ðɛɹz nʌθɪŋ ɹɪtʃ foʊks lʌv mɔɹ/",
    "chinese_translation": "有钱人最爱不过",
