    "song_order": "5",
    "song_title": "The Schuyler Sisters",
    "song_title_zh": "",
    "song_id": "05-the-schuyler-sisters",
    "line_index": "100",
    "english": "In the greatest city in the world!",
    "ipa": "/ɪnðə ɡɹeɪɾɪst sɪɾi ɪnðə wɜld/",
    "chinese_translation": "在世界上最伟大的城市！",
