    "song_title": "Right Hand Man",
    "song_title_zh": "",
    "song_id": "08-right-hand-man",
    "line_index": "51",
    "english": "Any hope of success is fleeting",
    "ipa": "/ɛni hoʊp ʌv səksɛs ɪz fliɾɪŋ/",
    "chinese_translation": "一丝胜利的希望正支离破碎",
