    "song_title_zh": "",
    "song_id": "08-right-hand-man",
    "line_index": "56",
    "english": "We are outgunned",
    "ipa": "/wi ɑɹ aʊtɡʌnd/",
    "chinese_translation": "我们装备告急",
    "note": "",
