    "song_title_zh": "",
    "song_id": "10-helpless",
    "line_index": "73",
    "english": "Eliza, I don't have a dollar to my name",
    "ipa": "/ɪlaɪzə aɪ doʊnt hæv ɐ dɑlɚ tə maɪ neɪm/",
    "chinese_translation": "伊莉莎，我一文不值",
