    "song_title": "Helpless",
    "song_title_zh": "",
    "song_id": "10-helpless",
    "line_index": "76",
    "english": "A couple of college credits and my top-notch brain",
    "ipa": "/ɐ kʌpəl ʌv kɑlɪdʒ kɹɛdɪts ænd maɪ tɑpnɑtʃ bɹeɪn/",
    "chinese_translation": "几个学分和智慧大脑",
