    "song_title_zh": "",
    "song_id": "11-satisfied",
    "line_index": "52",
    "english": "You strike me as a woman who has never been satisfied",
    "ipa": "/ju stɹaɪk mi æz ɐ wʊmən hu hɐz nɛvɚ bɪn sæɾɪsfaɪd/",
    "chinese_translation": "你打动了我，因为你是一个不会满足的女人",
