    "song_title": "Satisfied",
    "song_title_zh": "",
    "song_id": "11-satisfied",
    "line_index": "86",
    "english": "And I know she is",
    "ipa": "/ænd aɪ noʊ ʃi ɪz/",
    "chinese_translation": "我知道",
