    "song_order": "11",
    "song_title": "Satisfied",
    "song_title_zh": "",
    "song_id": "11-satisfied",
    "line_index": "87",
    "english": "Helpless",
    "ipa": "/hɛlpləs/",
    "chinese_translation": "她是那么的，无法自拔",
