    "song_title_zh": "",
    "song_id": "11-satisfied",
    "line_index": "88",
    "english": "And her eyes are just",
    "ipa": "/ænd hɜɹ aɪz ɑɹ dʒʌst/",
    "chinese_translation": "她的双眸",
