    "song_title": "Satisfied",
    "song_title_zh": "",
    "song_id": "11-satisfied",
    "line_index": "98",
    "english": "My father has no sons so I'm the one",
    "ipa": "/maɪ fɑðɚ hɐz noʊ sʌnz soʊ aɪm ðə wʌn/",
