    "song_title": "Satisfied",
    "song_title_zh": "",
    "song_id": "11-satisfied",
    "line_index": "99",
    "english": "Who has to social climb for one",
    "ipa": "/hu hɐz tə soʊʃəl klaɪm fɔɹwʌn/",
