    "song_order": "11",
    "song_title": "Satisfied",
    "song_title_zh": "",
    "song_id": "11-satisfied",
    "line_index": "102",
    "english": "And Alexander is penniless",
    "ipa": "/ænd ælɪɡzændɚɹ ɪz pɛnɪləs/",
    "chinese_translation": "并且亚历山大身无分文",
