    "song_title_zh": "",
    "song_id": "24-what-d-i-miss",
    "line_index": "48",
    "english": "And that I'm already Senate-approved...",
    "ipa": "/ænd ðæt aɪm ɔlɹɛdi sɛnəɾɐpɹuvd/",
    "chinese_translation": "参议院已经一致通过了",
