    "song_id": "24-what-d-i-miss",
    "line_index": "53",
    "english": "I can't believe that we are free",
    "ipa": "/aɪ kænt bᵻliv ðæt wi ɑɹ fɹi/",
    "chinese_translation": "我真不敢相信我们自由了",
