    "song_title": "What'd I Miss",
    "song_title_zh": "",
    "song_id": "24-what-d-i-miss",
    "line_index": "68",
    "english": "I've been fighting for the South alone",
    "ipa": "/aɪv bɪn faɪɾɪŋ fɚðə saʊθ ɐloʊn/",
    "chinese_translation": "我单独为南方奋战已久",
