    "english": "Aaa-ooo!",
    "ipa": "/eɪeɪeɪuoʊ/",
    "chinese_translation": "啊——噢！",
    "note": "",
    "source_file": "Hamilton (Original Broadway Cast Recording) (3367211).md"
