    "song_title": "Take a Break",
    "song_title_zh": "",
    "song_id": "26-take-a-break",
    "line_index": "79",
    "english": "One stroke and you've consumed my waking days",
    "ipa": "/wʌn stɹoʊk ænd juv kənsumd maɪ weɪkɪŋ deɪz/",
    "chinese_translation": "一个笔画，就使我彻夜难眠",
